import{c as d,Q as e,j as r,m as a}from"./chunks/framework.rlpw0eGz.js";const m=JSON.parse('{"title":"CSS 中长度单位","description":"CSS 中长度单位 —— 2023-02-09","frontmatter":{"title":"CSS 中长度单位","description":"CSS 中长度单位 —— 2023-02-09","date":"2023-02-09T00:00:00.000Z"},"headers":[],"relativePath":"notes/CSS 中长度单位.md","filePath":"notes/CSS 中长度单位.md","lastUpdated":null}'),o={name:"notes/CSS 中长度单位.md"};function i(n,t,c,s,h,p){return e(),r("div",null,[...t[0]||(t[0]=[a('<h2 id="css-中长度单位" tabindex="-1">CSS 中长度单位 <a class="header-anchor" href="#css-中长度单位" aria-label="Permalink to &quot;CSS 中长度单位&quot;">​</a></h2><p class="note-date">2023-02-09</p><h3 id="相对单位长度" tabindex="-1">相对单位长度 <a class="header-anchor" href="#相对单位长度" aria-label="Permalink to &quot;相对单位长度&quot;">​</a></h3><table tabindex="0"><thead><tr><th>单位</th><th>描述</th><th>示例</th></tr></thead><tbody><tr><td>em</td><td>相对于自身 font-size（字体大小）属性的值，如果自身没有设置，则继承父元素 font-size 属性的值，1em 等同于 font-size 属性值，例如 font-size 的值为 16px，那么 1em 就等于 16px，2em 就等于 32px</td><td><code>p{line-height:2em;}</code></td></tr><tr><td>rem</td><td>相对于根元素的 font-size 属性的大小，比如根元素的 font-size 是 100px，那么 1.2rem 就相当于 120px</td><td><code>p{font-size: 1.2rem;}</code></td></tr><tr><td>ex</td><td>相对于所用字体中小写英文字母 x 的高度，若无法确定 x 的高度则使用 0.5em 计算</td><td><code>p{font-size: 1ex;}</code></td></tr><tr><td>ch</td><td>相对于所用字体中数字 0 的高度，若无法确定 0 的高度则使用 0.5em 计算</td><td><code>p{line-height: 3ch;}</code></td></tr><tr><td>vw</td><td>相对于浏览器窗口的宽度，1vw = 窗口宽度的 1%</td><td><code>p{font-size: 5vw;} </code></td></tr><tr><td>vh</td><td>相对于浏览器窗口的高度，1vh = 窗口高度的 1%</td><td><code>p{font-size: 5vh;} </code></td></tr><tr><td>vmin</td><td>vw 与 vh 中较小的值</td><td><code>p{font-size: 5vmin;} </code></td></tr><tr><td>vmax</td><td>vw 与 vh 中较大的值</td><td><code>p{font-size: 5vmax;} </code></td></tr><tr><td>%</td><td>相对于父元素宽度或字体大小的百分比</td><td><code>div{width: 55%}</code></td></tr></tbody></table><h3 id="绝对长度单位" tabindex="-1">绝对长度单位 <a class="header-anchor" href="#绝对长度单位" aria-label="Permalink to &quot;绝对长度单位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>单位</th><th>描述</th></tr></thead><tbody><tr><td>cm</td><td>厘米</td></tr><tr><td>mm</td><td>毫米</td></tr><tr><td>in</td><td>英寸（1in = 96px = 2.54cm）</td></tr><tr><td>px</td><td>像素（1px = 1/96in）</td></tr><tr><td>pt</td><td>point，是一种专用的印刷单位“磅”，也可以称为“点”（1pt = 1/72in）</td></tr><tr><td>pc</td><td>pica，中文可称为“派卡”，印刷行业用于描述字体大小的单位，相当于我国新四号铅字的尺寸（1pc = 12pt）</td></tr></tbody></table>',6)])])}const _=d(o,[["render",i]]);export{m as __pageData,_ as default};
